459→// ============================================================================
460→// 流式响应处理
461→// ============================================================================
462→
463→async function handleStreamResponse(
464→  upstream: globalThis.Response,
465→  res: Response,
466→  record: RequestRecord,
467→  startTime: number,
468→  sessionId: string,
469→  classificationType: ClassificationType,
470→  activeAgent: import('../shared/types.js').AgentBase | null,
471→): Promise<void> {
472→  if (!upstream.body) throw new Error('No response body for streaming');
473→
474→  // SSE 必须立刻发送 headers，不能等 buffer 满
475→  res.flushHeaders();
476→
477→  const reader  = upstream.body.getReader();
478→  const decoder = new TextDecoder();
479→  const chunks: string[] = [];
480→
481→  // ── 流式预处理：在转发给 Claude Code 之前即时处理 Agent tool_use ─────────────
482→  // 目的：消除 race condition
483→  //   Claude Code 在收到 content_block_stop 事件后立即 spawn sub-agent
484→  //   而 CCO 原来在流结束后才更新 tools_call_result_map
485→  //   导致 sub-agent 的首个请求到达时 map 里还没有父条目 → unclassified
486→  //
487→  // 修复方案：在每个 chunk 转发给 Claude Code 之前先扫描 SSE 事件，
488→  //   发现 Agent tool_use 完成时立即写入 map 并创建占位 sub-agent
489→  interface StreamBlockInfo {
490→    id: string;
491→    name: string;
492→    inputParts: string[];
493→  }
494→  const streamBlocks = new Map<number, StreamBlockInfo>();
495→  let lineBuffer = ''; // 处理跨 chunk 的不完整行
496→
497→  function processChunkEvents(chunk: string): void {
498→    if (!activeAgent || !sessionManager) return;
499→
500→    lineBuffer += chunk;
501→    const lines = lineBuffer.split('\n');
502→    lineBuffer = lines.pop() ?? ''; // 保留不完整的最后一行
503→
504→    for (const line of lines) {
505→      if (!line.startsWith('data: ') || line === 'data: [DONE]') continue;
506→      let evt: Record<string, unknown>;
507→      try { evt = JSON.parse(line.slice(6)) as Record<string, unknown>; }
508→      catch { continue; }
509→
510→      const evtType = evt['type'] as string | undefined;
511→      const idx = typeof evt['index'] === 'number' ? evt['index'] : 0;
512→
513→      if (evtType === 'content_block_start') {
514→        const block = evt['content_block'] as Record<string, unknown> | undefined;
515→        if (block?.['type'] === 'tool_use') {
516→          streamBlocks.set(idx, {
517→            id: (block['id'] as string) ?? '',
518→            name: (block['name'] as string) ?? '',
519→            inputParts: [],
520→          });
521→        }
522→      } else if (evtType === 'content_block_delta') {
523→        const delta = evt['delta'] as Record<string, unknown> | undefined;
524→        if (delta?.['type'] === 'input_json_delta' && typeof delta['partial_json'] === 'string') {
525→          streamBlocks.get(idx)?.inputParts.push(delta['partial_json'] as string);
526→        }
527→      } else if (evtType === 'content_block_stop') {
528→        const info = streamBlocks.get(idx);
529→        if (info?.name === 'Agent' && info.id) {
530→          // Agent tool_use 已完成 → 在转发给 Claude Code 之前立即注册
531→          try {
532→            const args = JSON.parse(info.inputParts.join('')) as Record<string, unknown>;
533→            const prompt = typeof args['prompt'] === 'string' ? args['prompt'] : '';
534→            // 写入父 agent 的 map（如果已存在则跳过，避免覆盖更完整的数据）
535→            if (!activeAgent.tools_call_result_map[info.id]) {
536→              activeAgent.tools_call_result_map[info.id] = {
537→                tool_name: 'Agent',
538→                arguments: args,
539→                is_finished: false,
540→                result: null,
541→              };
542→            }
543→            // 创建占位 sub-agent（如果还没有）
544→            if (!sessionManager.findSubAgentByToolCallId(activeAgent, info.id)) {
545→              sessionManager.createPlaceholderSubAgent(activeAgent, info.id, prompt);
546→            }
547→          } catch { /* JSON 解析失败，忽略；流结束后 processResponseClassification 会重建 */ }
548→        }
549→        streamBlocks.delete(idx);
550→      }
551→    }
552→  }
553→
554→  try {
555→    while (true) {
556→      const { done, value } = await reader.read();
557→      if (done) break;
558→      const chunk = decoder.decode(value, { stream: true });
559→      chunks.push(chunk);
560→      // ① 先扫描 Agent tool_use 完成事件并立即注册（消除 race condition）
561→      processChunkEvents(chunk);
562→      // ② 再转发给 Claude Code（此时 map 已包含最新条目）
563→      res.write(chunk);
564→    }
565→  } finally {
566→    // 无论成功还是出错，都要关闭响应
567→    res.end();
568→
569→    const fullText = chunks.join('');
570→    const { contentBlocks } = parseSSEResponse(fullText);
571→
572→    record.status = upstream.ok ? 'completed' : 'error';
573→
574→    // ── 更新 Session 状态 ─────────────────────────────────────────────────
575→    if (upstream.ok) {
576→      try {
577→        processResponseClassification(
578→          sessionId,
579→          classificationType,
580→          contentBlocks,
581→          record.model,
582→          activeAgent,
583→        );
584→      } catch (err) {
585→        console.error('[CCO] Response classification error:', err);
586→      }
587→    }
588→  }
589→}
