 11→// ============================================================================
 12→// 请求分类器 - 实现 docs/claude code 场景分析.md 中的决策树
 13→// ============================================================================
 14→
 15→/**
 16→ * 请求体中与分类相关的字段
 17→ */
 18→export interface RequestForClassification {
 19→  system?: unknown;
 20→  messages: AnthropicMessage[];
 21→  tools?: unknown[];
 22→}
 23→
 24→/**
 25→ * 对请求进行分类
 26→ *
 27→ * 决策树：
 28→ *   Step 1: 先检测特殊请求（不依赖 session 是否存在）
 29→ *     压缩指令 → compression（session 不存在时也能正确识别）
 30→ *     （suggestion 不再特殊处理，走正常分类流程，由全量同步保证下次请求覆盖）
 31→ *   Step 2: session 是否存在？
 32→ *     不存在 + 有 tools → main_agent（创建 Session）
 33→ *     不存在 + 无 tools → unclassified
 34→ *   Step 3: tools 为空？
 35→ *     → unclassified（命名等辅助请求）
 36→ *   Step 3.5: 压缩恢复状态？
 37→ *     session.pending_compression_summary === true → main_agent（压缩恢复）
 38→ *   Step 4: (sys_prompt, messages[:-1]) 匹配已有 agent？
 39→ *     匹配主智能体 → main_agent
 40→ *     匹配某个子智能体 → sub_agent_continue
 41→ *   Step 5: 是否有未完成的 Agent 工具调用？
 42→ *     有 → 根据 prompt 参数匹配 → sub_agent_new
 43→ *     没有 → unclassified
 44→ */
 45→export function classifyRequest(
 46→  session: Session | undefined,
 47→  requestBody: RequestForClassification,
 48→  manager: SessionManager,
 49→  sessionId: string,
 50→): Classification {
 51→  const { system: sysPrompt, messages, tools } = requestBody;
 52→
 53→  const lastMessage = messages[messages.length - 1];
 54→
 55→  // ── Step 1: 先检测特殊请求（无论 session 是否存在） ────────────────────────
 56→  // 必须在 Step 2 之前，否则 CCO 中途启动时首个请求恰好是压缩，会被误分类为 main_agent
 57→  // 注意：
 58→  //   1. 只检查最后一条消息的 text blocks，不检查 tool_result
 59→  //      压缩指令一定在 user 消息的 text block 中，而不是 tool_result 中
 60→  //      如果检查 tool_result，读取包含压缩关键词的文件内容会导致误判
 61→  //   2. 必须有 tools → 真正的压缩请求一定携带 tools
 62→  //      没有 tools 的辅助请求（命名、count_tokens 等）可能碰巧携带相同的消息历史
 63→  const hasTools = tools && Array.isArray(tools) && tools.length > 0;
 64→
 65→  if (hasTools && lastMessage && lastMessage.role === 'user') {
 66→    const lastTextOnly = getTextOnlyContent(lastMessage);
 67→
 68→    if (lastTextOnly.includes('Your task is to create a detailed summary of the conversation so far')) {
 69→      // session 可能不存在（CCO 中途启动），agent 字段允许为 undefined
 70→      return { type: 'compression', agent: session?.main_agent };
 71→    }
 72→  }
 73→
 74→  // ── Step 2: Session 是否存在？ ──────────────────────────────────────────────
 75→  if (!session) {
 76→    if (hasTools) {
 77→      return { type: 'main_agent' };
 78→    }
 79→    return { type: 'unclassified' };
 80→  }
 81→
 82→  const messageHistory = messages.slice(0, -1);
 83→
 84→  // ── Step 3: tools 为空 → 辅助请求（命名等），忽略 ──────────────────────────
 85→  if (!hasTools) {
 86→    return { type: 'unclassified' };
 87→  }
 88→
 89→  // ── Step 3.5: 压缩恢复状态？ ─────────────────────────────────────────────
 90→  // 压缩后 sys_prompt 和 messages 已清空，pending_compression_summary 标记为 true
 91→  // 下一个带 tools 的请求即为主智能体恢复
 92→  if (session.pending_compression_summary) {
 93→    return { type: 'main_agent', agent: session.main_agent };
 94→  }
 95→
 96→  // ── Step 4: 匹配已有 agent（sys_prompt + messages[:-1]） ──────────────────
 97→  if (manager.matchesMainAgent(session, sysPrompt, messageHistory)) {
 98→    return { type: 'main_agent', agent: session.main_agent };
 99→  }
100→
101→  const matchedSubAgent = manager.findMatchingAgent(session, sysPrompt, messageHistory);
102→  if (matchedSubAgent && matchedSubAgent !== session.main_agent) {
103→    return { type: 'sub_agent_continue', agent: matchedSubAgent };
104→  }
105→
106→  // ── Step 5: 是否存在未完成的 Agent 工具调用？ ─────────────────────────────
107→  // 只有当某个 agent 调用了 Agent 工具且尚未返回结果时，才可能是新子智能体
108→  const firstMessageContent = getFirstUserMessageText(
109→    lastMessage ? [...messageHistory, lastMessage] : messageHistory,
110→  );
111→
112→  if (firstMessageContent) {
113→    const parentResult = manager.findParentForSubAgent(session, firstMessageContent);
114→    if (parentResult) {
115→      return {
116→        type: 'sub_agent_new',
117→        parentAgent: parentResult.parentAgent,
118→        toolCallId: parentResult.toolCallId,
119→      };
120→    }
121→  }
122→
123→  // 没有匹配到任何 pending Agent 调用 → 不是子智能体
124→  return { type: 'unclassified' };
125→}
126→
127→// ============================================================================
128→// 文本提取工具
129→// ============================================================================
130→
131→/**
132→ * 从 Anthropic system 字段（数组或字符串）中提取纯文本
133→ * 用于压缩恢复时的摘要匹配
134→ */
135→function extractSystemText(system: unknown): string {
136→  if (typeof system === 'string') return system;
137→  if (Array.isArray(system)) {
138→    return system
139→      .filter((b: unknown) => typeof b === 'object' && b !== null && (b as Record<string, unknown>).type === 'text' && typeof (b as Record<string, unknown>).text === 'string')
140→      .map((b: unknown) => (b as Record<string, string>).text)
141→      .join('\n');
142→  }
143→  return '';
144→}
145→
146→/**
147→ * 仅提取消息中 text 类型 block 的文本（不包含 tool_result）
148→ * 用于压缩指令检测，避免 tool_result 中的文件内容导致误判
149→ */
150→function getTextOnlyContent(msg: AnthropicMessage): string {
151→  if (typeof msg.content === 'string') return msg.content;
152→  if (Array.isArray(msg.content)) {
153→    return msg.content
154→      .filter(block => block.type === 'text' && block.text)
155→      .map(block => block.text)
156→      .join('\n');
157→  }
158→  return '';
159→}
160→
161→/**
162→ * 提取消息的完整文本内容（包括所有 text blocks 和 tool_result）
163→ */
164→function getFullMessageText(msg: AnthropicMessage): string {
165→  if (typeof msg.content === 'string') return msg.content;
166→  if (Array.isArray(msg.content)) {
167→    return msg.content
168→      .map(block => {
169→        if (block.type === 'text' && block.text) return block.text;
170→        if (block.type === 'tool_result' && typeof block.content === 'string') return block.content;
171→        return '';
172→      })
173→      .join('\n');
174→  }
175→  return '';
176→}
177→
178→/**
179→ * 获取 messages 中首条 user message 的文本内容
180→ * 用于子智能体关联（prompt IN user_message 匹配）
181→ */
182→function getFirstUserMessageText(messages: AnthropicMessage[]): string {
183→  const firstUser = messages.find(m => m.role === 'user');
184→  return firstUser ? getFullMessageText(firstUser) : '';
185→}
186→
187→export { getFullMessageText, extractSystemText };
