 12→// ============================================================================
 13→// SessionManager - 内存中维护所有活跃 Session，提供查找/创建/更新接口
 14→// ============================================================================
 15→
 16→export class SessionManager {
 17→  private sessions = new Map<string, Session>();
 18→
 19→  // ── 查询 ────────────────────────────────────────────────────────────────────
 20→
 21→  getSession(sessionId: string): Session | undefined {
 22→    return this.sessions.get(sessionId);
 23→  }
 24→
 25→  getAllSessions(): Session[] {
 26→    return [...this.sessions.values()];
 27→  }
 28→
 29→  // ── 创建 Session ─────────────────────────────────────────────────────────────
 30→
 31→  /**
 32→   * 创建新 Session + MainAgent
 33→   * 首次请求时调用
 34→   */
 35→  createSession(
 36→    sessionId: string,
 37→    sysPrompt: unknown,
 38→    messages: AnthropicMessage[],
 39→    tools: unknown[],
 40→  ): Session {
 41→    const now = new Date().toISOString();
 42→
 43→    // 提取首条 user message 的最后一个 text block 作为默认 session_name
 44→    const firstUserMsg = messages.find(m => m.role === 'user');
 45→    let defaultName = 'Untitled Session';
 46→    if (firstUserMsg) {
 47→      if (typeof firstUserMsg.content === 'string') {
 48→        defaultName = firstUserMsg.content;
 49→      } else if (Array.isArray(firstUserMsg.content)) {
 50→        const textBlocks = firstUserMsg.content.filter(b => b.type === 'text' && b.text);
 51→        if (textBlocks.length > 0) {
 52→          defaultName = (textBlocks[textBlocks.length - 1].text as string) || 'Untitled Session';
 53→        }
 54→      }
 55→    }
 56→    // session_name 最多 10 个字符
 57→    if (defaultName.length > 10) {
 58→      defaultName = defaultName.slice(0, 10);
 59→    }
 60→
 61→    const mainAgent: MainAgent = {
 62→      agent_id: generateId(),
 63→      current_sys_prompt: sysPrompt,
 64→      current_messages: [],       // 由每次请求全量同步
 65→      tools,
 66→      tools_call_result_map: {},
 67→      session_history_list: [],
 68→      sub_agents: [],
 69→    };
 70→
 71→    const session: Session = {
 72→      session_id: sessionId,
 73→      session_name: defaultName,
 74→      main_agent: mainAgent,
 75→      created_at: now,
 76→      updated_at: now,
 77→      stats: createEmptyStats(),
 78→    };
 79→
 80→    this.sessions.set(sessionId, session);
 81→    return session;
 82→  }
 83→
 84→  /**
 85→   * 从持久化数据加载 Session（服务器重启时）
 86→   */
 87→  loadSession(session: Session): void {
 88→    this.sessions.set(session.session_id, session);
 89→  }
 90→
 91→  // ── Agent 匹配 ──────────────────────────────────────────────────────────────
 92→
 93→  /**
 94→   * 在 session 中查找与 (sysPrompt, messageHistory) 匹配的 agent
 95→   * messageHistory = request.messages[:-1]（去掉最后一条消息）
 96→   * 返回匹配到的 agent，或 null
 97→   */
 98→  findMatchingAgent(
 99→    session: Session,
100→    sysPrompt: unknown,
101→    messageHistory: AnthropicMessage[],
102→  ): AgentBase | null {
103→    // 先检查主智能体
104→    if (matchesAgent(session.main_agent, sysPrompt, messageHistory)) {
105→      return session.main_agent;
106→    }
107→
108→    // 递归检查所有子智能体
109→    return findInSubAgents(session.main_agent.sub_agents, sysPrompt, messageHistory);
110→  }
111→
112→  /**
113→   * 判断请求是否匹配主智能体
114→   */
115→  matchesMainAgent(
116→    session: Session,
117→    sysPrompt: unknown,
118→    messageHistory: AnthropicMessage[],
119→  ): boolean {
120→    return matchesAgent(session.main_agent, sysPrompt, messageHistory);
121→  }
122→
123→  // ── 子智能体 ────────────────────────────────────────────────────────────────
124→
125→  /**
126→   * 查找能关联到新子智能体的父 agent
127→   * 遍历所有 agent 的 tools_call_result_map，找到：
128→   *   tool_name == "Agent" && is_finished == false && arguments.prompt IN userMessage
129→   */
130→  findParentForSubAgent(
131→    session: Session,
132→    firstUserMessageContent: string,
133→  ): { parentAgent: AgentBase; toolCallId: string } | null {
134→    // 检查主智能体
135→    const mainResult = findAgentToolCall(session.main_agent, firstUserMessageContent);
136→    if (mainResult) return mainResult;
137→
138→    // 递归检查所有子智能体
139→    return findAgentToolCallInSubAgents(session.main_agent.sub_agents, firstUserMessageContent);
140→  }
141→
142→  /**
143→   * 创建子智能体并挂载到父 agent
144→   * agent_id 直接使用 toolCallId（父 agent 的 Agent tool_use id）
145→   */
146→  createSubAgent(
147→    parentAgent: AgentBase,
148→    toolCallId: string,
149→    prompt: string,
150→    sysPrompt: unknown,
151→    messages: AnthropicMessage[],
152→    tools: unknown[],
153→  ): SubAgent {
154→    const subAgent: SubAgent = {
155→      agent_id: toolCallId,
156→      prompt,
157→      is_finished: false,
158→      current_sys_prompt: sysPrompt,
159→      current_messages: [],
160→      tools,
161→      tools_call_result_map: {},
162→      sub_agents: [],
163→    };
164→
165→    // 挂载到父 agent
166→    if ('sub_agents' in parentAgent) {
167→      (parentAgent as MainAgent | SubAgent).sub_agents.push(subAgent);
168→    }
169→
170→    return subAgent;
171→  }
172→
173→  /**
174→   * 在响应阶段检测到 Agent tool_use 时，立即创建占位子智能体
175→   * agent_id = toolCallId，占位节点 messages/tools/sys_prompt 为空
176→   */
177→  createPlaceholderSubAgent(
178→    parentAgent: AgentBase,
179→    toolCallId: string,
180→    prompt: string,
181→  ): SubAgent {
182→    const subAgent: SubAgent = {
183→      agent_id: toolCallId,
184→      prompt,
185→      is_finished: false,
186→      current_sys_prompt: null,
187→      current_messages: [],
188→      tools: [],
189→      tools_call_result_map: {},
190→      sub_agents: [],
191→    };
192→
193→    if ('sub_agents' in parentAgent) {
194→      (parentAgent as MainAgent | SubAgent).sub_agents.push(subAgent);
195→    }
196→
197→    return subAgent;
198→  }
199→
200→  /**
201→   * 在 agent 的直接 sub_agents 中按 agent_id（= tool_call_id）查找
202→   * 用于将已有占位节点与后续到达的真实请求关联
203→   */
204→  findSubAgentByToolCallId(
205→    parentAgent: AgentBase,
206→    toolCallId: string,
207→  ): SubAgent | null {
208→    if (!('sub_agents' in parentAgent)) return null;
209→    const subs = (parentAgent as MainAgent | SubAgent).sub_agents;
210→    return subs.find(s => s.agent_id === toolCallId) ?? null;
211→  }
212→
213→  /**
214→   * 标记子智能体为已完成
215→   * 在 agent 的 sub_agents 中按 agent_id（= tool_call_id）查找并更新
216→   */
217→  markSubAgentFinished(agent: AgentBase, toolCallId: string): void {
218→    if (!('sub_agents' in agent)) return;
219→    const subs = (agent as MainAgent | SubAgent).sub_agents;
220→    const sub = subs.find(s => s.agent_id === toolCallId);
221→    if (sub) {
222→      sub.is_finished = true;
223→    }
224→  }
225→
226→  // ── 重命名 Session ──────────────────────────────────────────────────────────
227→
228→  renameSession(sessionId: string, newName: string): boolean {
229→    const session = this.sessions.get(sessionId);
230→    if (!session) return false;
231→    // session_name 最多 10 个字符
232→    session.session_name = newName.length > 10 ? newName.slice(0, 10) : newName;
233→    session.updated_at = new Date().toISOString();
234→    return true;
235→  }
236→
237→  // ── 删除 Session（内存） ──────────────────────────────────────────────────────
238→
239→  removeSession(sessionId: string): boolean {
240→    return this.sessions.delete(sessionId);
241→  }
242→
243→  // ── 更新时间戳 ──────────────────────────────────────────────────────────────
244→
245→  touch(session: Session): void {
246→    session.updated_at = new Date().toISOString();
247→  }
248→
249→  // ── 统计更新 ─────────────────────────────────────────────────────────────────
250→
251→  updateStats(
252→    session: Session,
253→    model: string,
254→  ): void {
255→    const s = session.stats;
256→    s.total_requests++;
257→    s.models_used[model] = (s.models_used[model] ?? 0) + 1;
258→  }
259→}
260→
261→// ============================================================================
262→// 内部工具函数
263→// ============================================================================
264→
265→function createEmptyStats(): SessionStats {
266→  return {
267→    total_requests: 0,
268→    models_used: {},
269→  };
270→}
271→
272→/**
273→ * 匹配用的头部消息数量上限
274→ *
275→ * 只比较 current_messages 和 messageHistory 的前 HEAD_MATCH_COUNT 条消息，
276→ * 加上 sys_prompt 一致即视为匹配。
277→ *
278→ * 为什么这样做：
279→ *   1. 前几条消息是对话的"指纹"，最稳定，不受中途请求失败影响
280→ *   2. 避免全量逐条比较 → 当中间某个请求被 hook 拦截或上游 API 报错时，
281→ *      current_messages 可能被提前(eagerly)更新，导致全量前缀匹配断裂
282→ *   3. O(1) 复杂度，不随对话长度增长
283→ */
284→const HEAD_MATCH_COUNT = 4;
285→
286→/**
287→ * 判断 agent 是否与 (sysPrompt, messageHistory) 匹配
288→ *
289→ * 匹配逻辑：
290→ *   1. sys_prompt 必须一致（忽略 cache_control）
291→ *   2. 比较双方前 HEAD_MATCH_COUNT 条消息（取实际可比较的最小长度）
292→ *      —— 即 min(stored.length, incoming.length, HEAD_MATCH_COUNT)
293→ *   3. 至少有 1 条消息能比较，或者双方都为空
294→ *
295→ * 注意：Claude Code 会动态给消息 block 加 cache_control 字段，
296→ *       同一条消息在不同请求中 cache_control 位置不同，
297→ *       所以比较时必须忽略 cache_control
298→ */
299→function matchesAgent(
300→  agent: AgentBase,
301→  sysPrompt: unknown,
302→  messageHistory: AnthropicMessage[],
303→): boolean {
304→  // Step 1: sys_prompt 必须一致
305→  if (!deepEqualIgnoreCache(agent.current_sys_prompt, sysPrompt)) {
306→    return false;
307→  }
308→
309→  const storedLen = agent.current_messages.length;
310→  const incomingLen = messageHistory.length;
311→
312→  // 双方都为空 → 仅凭 sys_prompt 匹配（新建 session 的首次请求）
313→  if (storedLen === 0 && incomingLen === 0) {
314→    return true;
315→  }
316→
317→  // 一方有消息一方没有 → 仍然允许（agent 刚创建还没存消息，或压缩后清空了）
318→  if (storedLen === 0 || incomingLen === 0) {
319→    return true;
320→  }
321→
322→  // Step 2: 比较前 HEAD_MATCH_COUNT 条消息
323→  const compareLen = Math.min(storedLen, incomingLen, HEAD_MATCH_COUNT);
324→
325→  for (let i = 0; i < compareLen; i++) {
326→    if (!deepEqualIgnoreCache(agent.current_messages[i], messageHistory[i])) {
327→      return false;
328→    }
329→  }
330→
331→  return true;
332→}
333→
334→/**
335→ * 深度比较，忽略 cache_control 字段
336→ */
337→function deepEqualIgnoreCache(a: unknown, b: unknown): boolean {
338→  return JSON.stringify(a, cacheReplacer) === JSON.stringify(b, cacheReplacer);
339→}
340→
341→function cacheReplacer(key: string, value: unknown): unknown {
342→  if (key === 'cache_control') return undefined;
343→  return value;
344→}
345→
346→/**
347→ * 递归在子智能体列表中查找匹配的 agent
348→ */
349→function findInSubAgents(
350→  subAgents: SubAgent[],
351→  sysPrompt: unknown,
352→  messageHistory: AnthropicMessage[],
353→): AgentBase | null {
354→  for (const sub of subAgents) {
355→    if (matchesAgent(sub, sysPrompt, messageHistory)) {
356→      return sub;
357→    }
358→    // 递归检查子智能体的子智能体
359→    const found = findInSubAgents(sub.sub_agents, sysPrompt, messageHistory);
360→    if (found) return found;
361→  }
362→  return null;
363→}
364→
365→/**
366→ * 在 agent 的 tools_call_result_map 中查找 Agent 工具调用
367→ */
368→function findAgentToolCall(
369→  agent: AgentBase,
370→  userMessageContent: string,
371→): { parentAgent: AgentBase; toolCallId: string } | null {
372→  for (const [callId, entry] of Object.entries(agent.tools_call_result_map)) {
373→    if (
374→      entry.tool_name === 'Agent' &&
375→      !entry.is_finished &&
376→      typeof entry.arguments === 'object' &&
377→      entry.arguments !== null &&
378→      'prompt' in entry.arguments &&
379→      typeof (entry.arguments as Record<string, unknown>).prompt === 'string' &&
380→      userMessageContent.includes((entry.arguments as Record<string, unknown>).prompt as string)
381→    ) {
382→      return { parentAgent: agent, toolCallId: callId };
383→    }
384→  }
385→  return null;
386→}
387→
388→/**
389→ * 递归在子智能体列表中查找 Agent 工具调用
390→ */
391→function findAgentToolCallInSubAgents(
392→  subAgents: SubAgent[],
393→  userMessageContent: string,
394→): { parentAgent: AgentBase; toolCallId: string } | null {
395→  for (const sub of subAgents) {
396→    const result = findAgentToolCall(sub, userMessageContent);
397→    if (result) return result;
398→    const nested = findAgentToolCallInSubAgents(sub.sub_agents, userMessageContent);
399→    if (nested) return nested;
400→  }
401→  return null;
402→}
403→
404→/**
405→ * 深度比较两个值（用于系统提示词比较）
406→ */
407→function deepEqual(a: unknown, b: unknown): boolean {
408→  if (a === b) return true;
409→  if (a == null || b == null) return a == b;
410→  return JSON.stringify(a) === JSON.stringify(b);
411→}
412→
413→/**
414→ * 从消息中提取文本内容
415→ */
416→function extractTextFromMessage(msg: AnthropicMessage | undefined): string {
417→  if (!msg) return '';
418→  if (typeof msg.content === 'string') return msg.content;
419→  if (Array.isArray(msg.content)) {
420→    const textBlocks = msg.content
421→      .filter(b => b.type === 'text' && b.text)
422→      .map(b => b.text as string);
423→    return textBlocks.join('\n');
424→  }
425→  return '';
426→}
427→
428→// 导出工具函数（供 classifier 使用）
429→export { extractTextFromMessage, matchesAgent };
430→

  1→// ============================================================================
  2→// CCO 核心数据类型定义
  3→// ============================================================================
  4→
  5→// ── Anthropic API 基础类型 ──────────────────────────────────────────────────
  6→
  7→export interface AnthropicMessage {
  8→  role: 'user' | 'assistant';
  9→  content: string | AnthropicContentBlock[];
 10→}
 11→
 12→export interface AnthropicContentBlock {
 13→  type: 'text' | 'tool_use' | 'tool_result' | 'thinking' | 'image';
 14→  // text block
 15→  text?: string;
 16→  // thinking block
 17→  thinking?: string;
 18→  // tool_use block
 19→  id?: string;
 20→  name?: string;
 21→  input?: Record<string, unknown>;
 22→  // tool_result block
 23→  tool_use_id?: string;
 24→  content?: string | AnthropicContentBlock[];
 25→  is_error?: boolean;
 26→  // 其他扩展字段
 27→  [key: string]: unknown;
 28→}
 29→
 30→export interface TokenUsage {
 31→  input_tokens: number;
 32→  output_tokens: number;
 33→  cache_creation_input_tokens?: number;
 34→  cache_read_input_tokens?: number;
 35→}
 36→
 37→// ── 工具调用追踪 ────────────────────────────────────────────────────────────
 38→
 39→export interface ToolCallEntry {
 40→  tool_name: string;
 41→  arguments: Record<string, unknown>;
 42→  is_finished: boolean;
 43→  result: unknown;
 44→}
 45→
 46→// ── Agent 基础接口 ──────────────────────────────────────────────────────────
 47→
 48→export interface AgentBase {
 49→  agent_id: string;
 50→  current_sys_prompt: unknown;                      // Anthropic system 格式（数组或字符串）
 51→  current_messages: AnthropicMessage[];              // 当前对话历史（Anthropic 格式）
 52→  tools: unknown[];                                  // 工具定义列表
 53→  tools_call_result_map: Record<string, ToolCallEntry>;
 54→}
 55→
 56→// ── 主智能体 ────────────────────────────────────────────────────────────────
 57→
 58→export interface MainAgent extends AgentBase {
 59→  session_history_list: SessionHistoryEntry[];        // 压缩归档
 60→  sub_agents: SubAgent[];
 61→}
 62→
 63→export interface SessionHistoryEntry {
 64→  sys_prompt: unknown;
 65→  messages: AnthropicMessage[];
 66→  sub_agents: SubAgent[];                            // 归档时的子智能体快照
 67→  tools_call_result_map: Record<string, ToolCallEntry>; // 用于重建子智能体标签
 68→  archived_at: string;                               // ISO 8601
 69→}
 70→
 71→// ── 子智能体 ────────────────────────────────────────────────────────────────
 72→
 73→export interface SubAgent extends AgentBase {
 74→  // agent_id 直接使用父 agent 的 tool_call_id（即 tools_call_result_map 的 key）
 75→  // 这样 tool_result.tool_use_id === sub_agent.agent_id，天然关联
 76→  prompt: string;                                    // Agent 工具调用的 prompt 参数，用于身份辨识
 77→  is_finished: boolean;                              // 该子智能体是否已完成任务（由父 agent 的 tool_result 驱动）
 78→  sub_agents: SubAgent[];                            // general-purpose 子智能体可再调 Agent
 79→}
 80→
 81→// ── Session ─────────────────────────────────────────────────────────────────
 82→
 83→export interface Session {
 84→  session_id: string;
 85→  session_name: string;                              // 默认为首条 user message，可被命名请求更新
 86→  main_agent: MainAgent;
 87→  created_at: string;                                // ISO 8601
 88→  updated_at: string;                                // ISO 8601
 89→  stats: SessionStats;
 90→  pending_compression_summary?: boolean;              // 压缩后待恢复标记（true 表示下一个请求应恢复为主智能体）
 91→}
 92→
 93→export interface SessionStats {
 94→  total_requests: number;
 95→  models_used: Record<string, number>;               // model → 调用次数
 96→}
 97→
 98→// ── Session 列表概要（给 API 返回用） ───────────────────────────────────────
 99→
100→export interface SessionSummary {
101→  session_id: string;
102→  session_name: string;
103→  created_at: string;
104→  updated_at: string;
105→  stats: SessionStats & {
106→    conversation_rounds?: number;
107→    sub_agent_count?: number;
108→    compression_count?: number;
109→  };
110→}
111→
112→// ── 配置 ────────────────────────────────────────────────────────────────────
113→
114→export interface CcoConfig {
115→  version: string;
116→  port: number;
117→  dataDir: string;
118→  sessionsDir: string;
119→  apiBaseUrl: string;                                    // Anthropic API 地址（支持中转）
120→  logLevel: 'debug' | 'info' | 'warn' | 'error';
121→}
122→
123→// ── API 响应格式 ────────────────────────────────────────────────────────────
124→
125→export interface ApiResponse<T> {
126→  success: boolean;
127→  data?: T;
128→  error?: string;
129→}
130→
131→// ── 请求记录（仅 interceptor 内部流转，不再持久化） ─────────────────────────
132→
133→export interface RequestRecord {
134→  id: string;
135→  sessionId: string;
136→  timestamp: string;                                 // ISO 8601
137→  model: string;
138→  endpoint: string;
139→  request: Record<string, unknown>;
140→  response?: Record<string, unknown>;
141→  status: 'pending' | 'completed' | 'error';
142→  error?: string;
143→  classification?: ClassificationType;               // 请求分类标签
144→}
145→
146→// ── 请求分类 ────────────────────────────────────────────────────────────────
147→
148→export type ClassificationType =
149→  | 'main_agent'
150→  | 'compression'
151→  | 'sub_agent_new'
152→  | 'sub_agent_continue'
