315→ *
316→ * 匹配逻辑：
317→ *   1. sys_prompt 必须一致（忽略 cache_control）
318→ *   2. 比较双方前 HEAD_MATCH_COUNT 条消息（取实际可比较的最小长度）
319→ *      —— 即 min(syncedLen, incoming.length, HEAD_MATCH_COUNT)
320→ *      —— syncedLen = _synced_message_count ?? stored.length
321→ *      —— 只比较全量同步过的消息，忽略响应阶段 append 的 assistant 消息
322→ *      —— 因为 SSE 重建的 assistant 消息可能与 CC 下次发送的版本不一致
323→ *         （thinking block 的 signature、JSON key 顺序等差异）
324→ *   3. 至少有 1 条消息能比较，或者双方都为空
325→ *
326→ * 注意：Claude Code 会动态给消息 block 加 cache_control 字段，
327→ *       同一条消息在不同请求中 cache_control 位置不同，
328→ *       所以比较时必须忽略 cache_control
329→ */
330→function matchesAgent(
331→  agent: AgentBase,
332→  sysPrompt: unknown,
333→  messageHistory: AnthropicMessage[],
334→): MatchResult {
335→  // Step 1: sys_prompt 必须一致
336→  if (!deepEqualIgnoreCache(agent.current_sys_prompt, sysPrompt)) {
337→    return { matched: false, reason: 'sys✗' };
338→  }
339→
340→  // 使用全量同步时的消息数量，忽略响应阶段 append 的 assistant 消息
341→  const syncedLen = agent._synced_message_count ?? agent.current_messages.length;
342→  const incomingLen = messageHistory.length;
343→
344→  // 双方都为空 → 仅凭 sys_prompt 匹配（新建 session 的首次请求）
345→  if (syncedLen === 0 && incomingLen === 0) {
346→    return { matched: true, reason: 'sys✓ both_empty' };
347→  }
348→
349→  // 一方有消息一方没有 → 仍然允许（agent 刚创建还没存消息，或压缩后清空了）
350→  if (syncedLen === 0 || incomingLen === 0) {
351→    return { matched: true, reason: `sys✓ one_empty(synced=${syncedLen},incoming=${incomingLen})` };
352→  }
353→
354→  // Step 2: 比较前 HEAD_MATCH_COUNT 条消息
355→  const compareLen = Math.min(syncedLen, incomingLen, HEAD_MATCH_COUNT);
356→
357→  for (let i = 0; i < compareLen; i++) {
358→    if (!deepEqualIgnoreCache(agent.current_messages[i], messageHistory[i])) {
359→      return { matched: false, reason: `sys✓ head✗(idx=${i},synced=${syncedLen},incoming=${incomingLen},compared=${compareLen})` };
360→    }
361→  }
362→
363→  return { matched: true, reason: `sys✓ head✓(synced=${syncedLen},incoming=${incomingLen},compared=${compareLen})` };
364→}
