366→/**
367→ * 深度比较，忽略 cache_control 字段
368→ */
369→function deepEqualIgnoreCache(a: unknown, b: unknown): boolean {
370→  return JSON.stringify(a, cacheReplacer) === JSON.stringify(b, cacheReplacer);
371→}
372→
373→function cacheReplacer(key: string, value: unknown): unknown {
374→  if (key === 'cache_control') return undefined;
375→  return value;
376→}
