119→
120→  if (req.headers['anthropic-beta']) {
121→    headers['anthropic-beta'] = req.headers['anthropic-beta'] as string;
122→  }
123→
124→  try {
125→    const upstream = await fetch(targetUrl, {
126→      method:  'POST',
127→      headers,
128→      body:    JSON.stringify(req.body),
129→    });
130→
131→    const contentType = upstream.headers.get('content-type') ?? '';
132→    res.status(upstream.status);
133→
134→    // 转发响应头，但跳过 hop-by-hop 头（由代理自身管理）
135→    const skipHeaders = new Set(['content-encoding', 'content-length', 'transfer-encoding']);
136→    upstream.headers.forEach((value, key) => {
137→      if (!skipHeaders.has(key.toLowerCase())) {
138→        res.setHeader(key, value);
139→      }
140→    });
141→
142→    if (contentType.includes('text/event-stream')) {
143→      await handleStreamResponse(upstream, res, record, startTime, sessionId, classificationType, activeAgent);
144→    } else {
145→      await handleJsonResponse(upstream, res, record, startTime, sessionId, classificationType, activeAgent);
146→    }
147→  } catch (err) {
148→    const error = err instanceof Error ? err.message : String(err);
149→    record.status = 'error';
150→    record.error  = error;
151→
152→    if (!res.headersSent) {
153→      res.status(502).json({ error: 'Upstream request failed', detail: error });
154→    }
155→  }
156→}
157→
158→// ============================================================================
159→// 补偿历史子智能体 — 为 tools_call_result_map 中的 Agent 调用创建占位 SubAgent
160→// 处理 CCO 中途启动 / 历史数据缺失的场景
161→// ============================================================================
162→
163→function backfillSubAgents(agent: import('../shared/types.js').AgentBase & { sub_agents?: import('../shared/types.js').SubAgent[] }): void {
164→  if (!('sub_agents' in agent)) return;
165→  const typedAgent = agent as import('../shared/types.js').MainAgent | import('../shared/types.js').SubAgent;
166→
167→  // 收集已有 sub_agents 的 agent_id（= tool_call_id）
168→  const existingIds = new Set(typedAgent.sub_agents.map(s => s.agent_id));
169→
170→  // 扫描所有 Agent 工具调用
171→  for (const [callId, entry] of Object.entries(agent.tools_call_result_map)) {
172→    if (entry.tool_name !== 'Agent') continue;
173→    if (existingIds.has(callId)) continue;
174→
175→    // 创建占位 SubAgent，agent_id = callId，填充 prompt 和 is_finished
176→    const args = entry.arguments as Record<string, unknown>;
177→    const prompt = typeof args.prompt === 'string' ? args.prompt : '';
178→    const placeholderSub: import('../shared/types.js').SubAgent = {
179→      agent_id: callId,
180→      prompt,
181→      is_finished: entry.is_finished,
182→      current_sys_prompt: null,
183→      current_messages: [],
184→      tools: [],
185→      tools_call_result_map: {},
186→      sub_agents: [],
187→    };
188→
189→    typedAgent.sub_agents.push(placeholderSub);
190→  }
191→}
192→
193→// ============================================================================
194→// 从全量 messages 重建 tools_call_result_map
195→// ============================================================================
196→
197→/**
198→ * 扫描所有 messages 中的 tool_use 和 tool_result，重建 tools_call_result_map
199→ * 每次请求的 messages 包含完整历史，所以直接全量重建
200→ * 同时同步子智能体的 is_finished 状态
201→ */
202→function syncToolCallMap(
203→  agent: import('../shared/types.js').AgentBase,
204→  messages: import('../shared/types.js').AnthropicMessage[],
205→): void {
206→  const map: Record<string, import('../shared/types.js').ToolCallEntry> = {};
207→
208→  // 第一遍：收集所有 tool_use
209→  for (const msg of messages) {
210→    if (msg.role === 'assistant' && Array.isArray(msg.content)) {
211→      for (const block of msg.content as AnthropicContentBlock[]) {
212→        if (block.type === 'tool_use' && block.id && block.name) {
213→          map[block.id] = {
214→            tool_name: block.name,
215→            arguments: (block.input ?? {}) as Record<string, unknown>,
216→            is_finished: false,
217→            result: null,
218→          };
219→        }
220→      }
221→    }
222→  }
223→
224→  // 第二遍：匹配 tool_result
225→  for (const msg of messages) {
226→    if (msg.role === 'user' && Array.isArray(msg.content)) {
227→      for (const block of msg.content as AnthropicContentBlock[]) {
228→        if (block.type === 'tool_result' && block.tool_use_id && map[block.tool_use_id]) {
229→          map[block.tool_use_id].is_finished = true;
230→          map[block.tool_use_id].result = block.content ?? null;
231→        }
232→      }
233→    }
234→  }
235→
236→  agent.tools_call_result_map = map;
237→
238→  // 同步子智能体的 is_finished 状态：
239→  // 当 tool_result 返回时意味着对应子智能体已完成任务
240→  if (sessionManager && 'sub_agents' in agent) {
241→    for (const [callId, entry] of Object.entries(map)) {
242→      if (entry.tool_name === 'Agent' && entry.is_finished) {
243→        sessionManager.markSubAgentFinished(agent, callId);
244→      }
245→    }
246→  }
247→}
248→
249→// ============================================================================
250→// 请求阶段：根据分类更新 Session 状态
251→// ============================================================================
252→
253→function processRequestClassification(
254→  sessionId: string,
255→  type: ClassificationType,
256→  requestBody: RequestForClassification,
257→  classification: { agent?: unknown; parentAgent?: unknown; toolCallId?: string },
258→): import('../shared/types.js').AgentBase | null {
259→  if (!sessionManager) return null;
260→
261→  const { system: sysPrompt, messages, tools } = requestBody;
262→  // 存储时去掉 cache_control，避免后续比较不一致
263→  const cleanMessages = JSON.parse(JSON.stringify(messages, (k, v) => k === 'cache_control' ? undefined : v)) as AnthropicMessage[];
264→
265→  switch (type) {
266→    case 'main_agent': {
267→      let session = sessionManager.getSession(sessionId);
268→      if (!session) {
269→        session = sessionManager.createSession(sessionId, sysPrompt, messages, tools ?? []);
270→      }
271→      const mainAgent = session.main_agent;
272→
273→      // 压缩恢复：更新 sys_prompt（压缩后 sys_prompt 已清空，需要用新请求的 sys_prompt 恢复）
274→      if (session.pending_compression_summary) {
275→        mainAgent.current_sys_prompt = sysPrompt;
276→        delete session.pending_compression_summary;
277→        console.log('[CCO] Compression recovery: sys_prompt updated, pending flag cleared');
278→      }
279→
280→      mainAgent.current_messages = cleanMessages;
281→      syncToolCallMap(mainAgent, cleanMessages);
282→      // 补偿历史子智能体：tools_call_result_map 中有 Agent 调用但 sub_agents 里没有对应节点
283→      backfillSubAgents(mainAgent);
284→      return mainAgent;
285→    }
286→
287→    case 'sub_agent_continue': {
288→      const agent = classification.agent;
289→      if (agent && typeof agent === 'object' && 'current_messages' in agent) {
290→        const typedAgent = agent as import('../shared/types.js').AgentBase;
291→        typedAgent.current_messages = cleanMessages;
292→        syncToolCallMap(typedAgent, cleanMessages);
293→        backfillSubAgents(typedAgent);
294→        return typedAgent;
295→      }
296→      return null;
297→    }
298→
299→    case 'sub_agent_new': {
300→      const session = sessionManager.getSession(sessionId);
301→      if (!session) return null;
302→
303→      const parentAgent = classification.parentAgent as import('../shared/types.js').AgentBase | undefined;
304→      const parent = parentAgent ?? session.main_agent;
305→      const toolCallId = classification.toolCallId ?? 'unknown';
306→
307→      // 先查找响应阶段已创建的占位 SubAgent
308→      const existingPlaceholder = sessionManager.findSubAgentByToolCallId(parent, toolCallId);
309→
310→      let subAgent: import('../shared/types.js').SubAgent;
311→      if (existingPlaceholder) {
312→        // 填充占位节点：更新 sys_prompt、tools
313→        existingPlaceholder.current_sys_prompt = sysPrompt;
314→        existingPlaceholder.tools = tools ?? [];
315→        subAgent = existingPlaceholder;
316→      } else {
317→        // 没有占位节点（CCO 中途启动等情况），创建新的
318→        const args = parent.tools_call_result_map[toolCallId]?.arguments as Record<string, unknown> | undefined;
319→        const prompt = typeof args?.prompt === 'string' ? args.prompt : '';
320→        subAgent = sessionManager.createSubAgent(
321→          parent,
322→          toolCallId,
323→          prompt,
324→          sysPrompt,
325→          messages,
326→          tools ?? [],
327→        );
328→      }
329→      subAgent.current_messages = cleanMessages;
330→      syncToolCallMap(subAgent, cleanMessages);
331→      return subAgent;
332→    }
333→
334→    case 'compression': {
335→      // 压缩请求阶段：确保 session 存在，并同步压缩前的历史消息
336→      // 这处理两种情况：
337→      //   1. 正常情况：session 已存在（Step 1 之前已创建）
338→      //   2. CCO 中途启动：首个请求就是压缩，session 尚不存在，需要先创建
339→      let session = sessionManager.getSession(sessionId);
340→      if (!session) {
341→        // CCO 中途启动场景：用压缩前的历史消息初始化 session
342→        // messages[:-1] 是对话历史，messages[-1] 是压缩指令（不归入历史）
343→        const preCompressionMessages = messages.slice(0, -1);
344→        session = sessionManager.createSession(sessionId, sysPrompt, preCompressionMessages, tools ?? []);
345→        console.log(`[CCO] Compression: session created on-the-fly (CCO started mid-session), msgs: ${preCompressionMessages.length}`);
346→
347→        // 同步工具调用历史，补建历史子智能体
348→        const cleanPreMsgs = JSON.parse(JSON.stringify(preCompressionMessages, (k, v) => k === 'cache_control' ? undefined : v)) as AnthropicMessage[];
349→        const mainAgent = session.main_agent;
350→        mainAgent.current_messages = cleanPreMsgs;
351→        syncToolCallMap(mainAgent, cleanPreMsgs);
352→        backfillSubAgents(mainAgent);
353→      }
354→      // session 已存在：不需要额外操作，响应阶段会执行归档
355→      return null;
356→    }
357→
358→    case 'unclassified':
359→      // 未分类请求完全忽略
360→      return null;
361→  }
362→}
363→
364→// ============================================================================
365→// 响应阶段：解析响应并更新 Session 状态
366→// ============================================================================
367→
368→function processResponseClassification(
369→  sessionId: string,
370→  type: ClassificationType,
371→  responseContent: AnthropicContentBlock[],
372→  model: string,
373→  activeAgent: import('../shared/types.js').AgentBase | null,
374→): void {
375→  if (!sessionManager) return;
376→
377→  const session = sessionManager.getSession(sessionId);
378→  if (!session) return;
379→
380→  // 更新统计信息（除了 unclassified）
381→  if (type !== 'unclassified') {
382→    sessionManager.updateStats(session, model);
383→  }
384→
385→  // 更新时间戳
386→  sessionManager.touch(session);
387→
388→  // ── 压缩响应处理：归档当前对话 + 重置主智能体状态 ─────────────────────────
389→  if (type === 'compression' && responseContent.length > 0) {
390→    // 1. 归档当前状态到 session_history_list
391→    const mainAgent = session.main_agent;
392→    const archiveEntry: SessionHistoryEntry = {
393→      sys_prompt: mainAgent.current_sys_prompt,
394→      messages: [...mainAgent.current_messages],
395→      sub_agents: mainAgent.sub_agents,                // 快照本轮全部子智能体
396→      tools_call_result_map: { ...mainAgent.tools_call_result_map }, // 用于重建标签
397→      archived_at: new Date().toISOString(),
398→    };
399→    mainAgent.session_history_list.push(archiveEntry);
400→
401→    // 2. 清空当前状态（sys_prompt + messages + sub_agents）
402→    //    压缩后 CC 会发送全新的 sys_prompt（含摘要），旧的已无法匹配
403→    //    全部置空后，下一个带 tools 的请求会自然匹配为主智能体（matchesAgent 空状态逻辑）
404→    mainAgent.current_sys_prompt = null;
405→    mainAgent.current_messages = [];
406→    mainAgent.sub_agents = [];
407→    mainAgent.tools_call_result_map = {};
408→
409→    // 3. 标记压缩后待恢复状态
410→    session.pending_compression_summary = true;
411→
412→    console.log(`[CCO] Compression archived: ${mainAgent.session_history_list.length} entries`);
413→  }
414→
415→  // 将本轮 assistant 响应追加到 current_messages，确保子 agent 完整对话可被查看
416→  // 下一次请求到来时，cleanMessages 会重新全量覆盖，不会产生重复
417→  if (activeAgent && responseContent.length > 0 && type !== 'unclassified') {
418→    const assistantMsg: AnthropicMessage = {
419→      role: 'assistant',
420→      content: responseContent,
421→    };
422→    activeAgent.current_messages.push(assistantMsg);
423→
424→    // 立即将响应中的 tool_use 写入 tools_call_result_map
425→    // 这样在子智能体的请求到达时（Step 4），能找到 pending 的 Agent 条目
426→    // 下次请求到来时 syncToolCallMap 会全量重建，不会重复
427→    for (const block of responseContent) {
428→      if (block.type === 'tool_use' && block.id && block.name) {
429→        activeAgent.tools_call_result_map[block.id] = {
430→          tool_name: block.name,
431→          arguments: (block.input ?? {}) as Record<string, unknown>,
432→          is_finished: false,
433→          result: null,
434→        };
435→
436→        // 对 Agent 工具调用，立即创建占位子智能体
437→        // 这样 Dashboard 能第一时间看到子智能体节点，无需等待子智能体首次请求
438→        if (block.name === 'Agent') {
439→          const args = (block.input ?? {}) as Record<string, unknown>;
440→          const prompt = typeof args.prompt === 'string' ? args.prompt : '';
441→          // 检查是否已有对应的 sub_agent（避免重复创建）
442→          const existing = sessionManager.findSubAgentByToolCallId(activeAgent, block.id);
443→          if (!existing) {
444→            sessionManager.createPlaceholderSubAgent(activeAgent, block.id, prompt);
445→          }
446→        }
447→      }
448→    }
449→  }
450→
451→  // ── 持久化 Session 到磁盘 ──────────────────────────────────────────────────
452→  try {
453→    saveSession(session);
454→  } catch (err) {
455→    console.error('[CCO] Failed to save session:', err);
456→  }
457→}
