toolu_bdrk_019pbFRfYr8Xb1fx3UjL9YXN.result:
  1→import type {
  2→  Session,
  3→  AnthropicMessage,
  4→  AnthropicContentBlock,
  5→  Classification,
  6→  ClassificationType,
  7→  AgentBase,
  8→} from '../shared/types.js';
  9→import { SessionManager, extractTextFromMessage } from './manager.js';
 10→
 11→// ============================================================================
 12→// 请求分类器 - 实现 docs/claude code 场景分析.md 中的决策树
 13→// ============================================================================
 14→
 15→/**
 16→ * 请求体中与分类相关的字段
 17→ */
 18→export interface RequestForClassification {
 19→  system?: unknown;
 20→  messages: AnthropicMessage[];
 21→  tools?: unknown[];
 22→}
 23→
 24→/**
 25→ * 对请求进行分类
 26→ *
 27→ * 决策树：
 28→ *   Step 1: 先检测特殊请求（不依赖 session 是否存在）
 29→ *     压缩指令 → compression（session 不存在时也能正确识别）
 30→ *     （suggestion 不再特殊处理，走正常分类流程，由全量同步保证下次请求覆盖）
 31→ *   Step 2: session 是否存在？
 32→ *     不存在 + 有 tools → main_agent（创建 Session）
 33→ *     不存在 + 无 tools → unclassified
 34→ *   Step 3: tools 为空？
 35→ *     → unclassified（命名等辅助请求）
 36→ *   Step 3.5: 压缩恢复状态？
 37→ *     session.pending_compression_summary === true → main_agent（压缩恢复）
 38→ *   Step 4: (sys_prompt, messages[:-1]) 匹配已有 agent？
 39→ *     匹配主智能体 → main_agent
 40→ *     匹配某个子智能体 → sub_agent_continue
 41→ *   Step 5: 是否有未完成的 Agent 工具调用？
 42→ *     有 → 根据 prompt 参数匹配 → sub_agent_new
 43→ *     没有 → unclassified
 44→ */
 45→export function classifyRequest(
 46→  session: Session | undefined,
 47→  requestBody: RequestForClassification,
 48→  manager: SessionManager,
 49→  sessionId: string,
 50→): Classification {
 51→  const { system: sysPrompt, messages, tools } = requestBody;
 52→
 53→  const lastMessage = messages[messages.length - 1];
 54→
 55→  // ── Step 1: 先检测特殊请求（无论 session 是否存在） ────────────────────────
 56→  // 必须在 Step 2 之前，否则 CCO 中途启动时首个请求恰好是压缩，会被误分类为 main_agent
 57→  // 注意：
 58→  //   1. 只检查最后一条消息的 text blocks，不检查 tool_result
 59→  //      压缩指令一定在 user 消息的 text block 中，而不是 tool_result 中
 60→  //      如果检查 tool_result，读取包含压缩关键词的文件内容会导致误判
 61→  //   2. 必须有 tools → 真正的压缩请求一定携带 tools
 62→  //      没有 tools 的辅助请求（命名、count_tokens 等）可能碰巧携带相同的消息历史
 63→  const hasTools = tools && Array.isArray(tools) && tools.length > 0;
 64→
 65→  if (hasTools && lastMessage && lastMessage.role === 'user') {
 66→    const lastTextOnly = getTextOnlyContent(lastMessage);
 67→
 68→    if (lastTextOnly.includes('Your task is to create a detailed summary of the conversation so far')) {
 69→      // session 可能不存在（CCO 中途启动），agent 字段允许为 undefined
 70→      return { type: 'compression', agent: session?.main_agent };
 71→    }
 72→  }
 73→
 74→  // ── Step 2: Session 是否存在？ ──────────────────────────────────────────────
 75→  if (!session) {
 76→    if (hasTools) {
 77→      return { type: 'main_agent' };
 78→    }
 79→    return { type: 'unclassified' };
 80→  }
 81→
 82→  const messageHistory = messages.slice(0, -1);
 83→
 84→  // ── Step 3: tools 为空 → 辅助请求（命名等），忽略 ──────────────────────────
 85→  if (!hasTools) {
 86→    return { type: 'unclassified' };
 87→  }
 88→
 89→  // ── Step 3.5: 压缩恢复状态？ ─────────────────────────────────────────────
 90→  // 压缩后 sys_prompt 和 messages 已清空，pending_compression_summary 标记为 true
 91→  // 下一个带 tools 的请求即为主智能体恢复
 92→  if (session.pending_compression_summary) {
 93→    return { type: 'main_agent', agent: session.main_agent };
 94→  }
 95→
 96→  // ── Step 4: 匹配已有 agent（sys_prompt + messages[:-1]） ──────────────────
 97→  if (manager.matchesMainAgent(session, sysPrompt, messageHistory)) {
 98→    return { type: 'main_agent', agent: session.main_agent };
 99→  }
100→
101→  const matchedSubAgent = manager.findMatchingAgent(session, sysPrompt, messageHistory);
102→  if (matchedSubAgent && matchedSubAgent !== session.main_agent) {
103→    return { type: 'sub_agent_continue', agent: matchedSubAgent };
104→  }
105→
106→  // ── Step 5: 是否存在未完成的 Agent 工具调用？ ─────────────────────────────
107→  // 只有当某个 agent 调用了 Agent 工具且尚未返回结果时，才可能是新子智能体
108→  const firstMessageContent = getFirstUserMessageText(
109→    lastMessage ? [...messageHistory, lastMessage] : messageHistory,
110→  );
111→
112→  if (firstMessageContent) {
113→    const parentResult = manager.findParentForSubAgent(session, firstMessageContent);
114→    if (parentResult) {
115→      return {
116→        type: 'sub_agent_new',
117→        parentAgent: parentResult.parentAgent,
118→        toolCallId: parentResult.toolCallId,
119→      };
120→    }
121→  }
122→
123→  // 没有匹配到任何 pending Agent 调用 → 不是子智能体
124→  return { type: 'unclassified' };
125→}
126→
127→// ============================================================================
128→// 文本提取工具
129→// ============================================================================
130→
131→/**
132→ * 从 Anthropic system 字段（数组或字符串）中提取纯文本
133→ * 用于压缩恢复时的摘要匹配
134→ */
135→function extractSystemText(system: unknown): string {
136→  if (typeof system === 'string') return system;
137→  if (Array.isArray(system)) {
138→    return system
139→      .filter((b: unknown) => typeof b === 'object' && b !== null && (b as Record<string, unknown>).type === 'text' && typeof (b as Record<string, unknown>).text === 'string')
140→      .map((b: unknown) => (b as Record<string, string>).text)
141→      .join('\n');
142→  }
143→  return '';
144→}
145→
146→/**
147→ * 仅提取消息中 text 类型 block 的文本（不包含 tool_result）
148→ * 用于压缩指令检测，避免 tool_result 中的文件内容导致误判
149→ */
150→function getTextOnlyContent(msg: AnthropicMessage): string {
151→  if (typeof msg.content === 'string') return msg.content;
152→  if (Array.isArray(msg.content)) {
153→    return msg.content
154→      .filter(block => block.type === 'text' && block.text)
155→      .map(block => block.text)
156→      .join('\n');
157→  }
158→  return '';
159→}
160→
161→/**
162→ * 提取消息的完整文本内容（包括所有 text blocks 和 tool_result）
163→ */
164→function getFullMessageText(msg: AnthropicMessage): string {
165→  if (typeof msg.content === 'string') return msg.content;
166→  if (Array.isArray(msg.content)) {
167→    return msg.content
168→      .map(block => {
169→        if (block.type === 'text' && block.text) return block.text;
170→        if (block.type === 'tool_result' && typeof block.content === 'string') return block.content;
171→        return '';
172→      })
173→      .join('\n');
174→  }
175→  return '';
176→}
177→
178→/**
179→ * 获取 messages 中首条 user message 的文本内容
180→ * 用于子智能体关联（prompt IN user_message 匹配）
181→ */
182→function getFirstUserMessageText(messages: AnthropicMessage[]): string {
183→  const firstUser = messages.find(m => m.role === 'user');
184→  return firstUser ? getFullMessageText(firstUser) : '';
185→}
186→
187→export { getFullMessageText, extractSystemText };
188→

toolu_bdrk_01EPU37kX2vWpiJV4UttW2Bo.result:
  1→import { generateId } from '../shared/utils.js';
  2→import type {
  3→  Session,
  4→  SessionStats,
  5→  MainAgent,
  6→  SubAgent,
  7→  AgentBase,
  8→  AnthropicMessage,
  9→  ToolCallEntry,
 10→} from '../shared/types.js';
 11→
 12→// ============================================================================
 13→// SessionManager - 内存中维护所有活跃 Session，提供查找/创建/更新接口
 14→// ============================================================================
 15→
 16→export class SessionManager {
 17→  private sessions = new Map<string, Session>();
 18→
 19→  // ── 查询 ────────────────────────────────────────────────────────────────────
 20→
 21→  getSession(sessionId: string): Session | undefined {
 22→    return this.sessions.get(sessionId);
 23→  }
 24→
 25→  getAllSessions(): Session[] {
 26→    return [...this.sessions.values()];
 27→  }
 28→
 29→  // ── 创建 Session ─────────────────────────────────────────────────────────────
 30→
 31→  /**
 32→   * 创建新 Session + MainAgent
 33→   * 首次请求时调用
 34→   */
 35→  createSession(
 36→    sessionId: string,
 37→    sysPrompt: unknown,
 38→    messages: AnthropicMessage[],
 39→    tools: unknown[],
 40→  ): Session {
 41→    const now = new Date().toISOString();
 42→
 43→    // 提取首条 user message 的最后一个 text block 作为默认 session_name
 44→    const firstUserMsg = messages.find(m => m.role === 'user');
 45→    let defaultName = 'Untitled Session';
 46→    if (firstUserMsg) {
 47→      if (typeof firstUserMsg.content === 'string') {
 48→        defaultName = firstUserMsg.content;
 49→      } else if (Array.isArray(firstUserMsg.content)) {
 50→        const textBlocks = firstUserMsg.content.filter(b => b.type === 'text' && b.text);
 51→        if (textBlocks.length > 0) {
 52→          defaultName = (textBlocks[textBlocks.length - 1].text as string) || 'Untitled Session';
 53→        }
 54→      }
 55→    }
 56→    // session_name 最多 10 个字符
 57→    if (defaultName.length > 10) {
 58→      defaultName = defaultName.slice(0, 10);
 59→    }
 60→
 61→    const mainAgent: MainAgent = {
 62→      agent_id: generateId(),
 63→      current_sys_prompt: sysPrompt,
 64→      current_messages: [],       // 由每次请求全量同步
 65→      tools,
 66→      tools_call_result_map: {},
 67→      session_history_list: [],
 68→      sub_agents: [],
 69→    };
 70→
 71→    const session: Session = {
 72→      session_id: sessionId,
 73→      session_name: defaultName,
 74→      main_agent: mainAgent,
 75→      created_at: now,
 76→      updated_at: now,
 77→      stats: createEmptyStats(),
 78→    };
 79→
 80→    this.sessions.set(sessionId, session);
 81→    return session;
 82→  }
 83→
 84→  /**
 85→   * 从持久化数据加载 Session（服务器重启时）
 86→   */
 87→  loadSession(session: Session): void {
 88→    this.sessions.set(session.session_id, session);
 89→  }
 90→
 91→  // ── Agent 匹配 ──────────────────────────────────────────────────────────────
 92→
 93→  /**
 94→   * 在 session 中查找与 (sysPrompt, messageHistory) 匹配的 agent
 95→   * messageHistory = request.messages[:-1]（去掉最后一条消息）
 96→   * 返回匹配到的 agent，或 null
 97→   */
 98→  findMatchingAgent(
 99→    session: Session,
100→    sysPrompt: unknown,
101→    messageHistory: AnthropicMessage[],
102→  ): AgentBase | null {
103→    // 先检查主智能体
104→    if (matchesAgent(session.main_agent, sysPrompt, messageHistory)) {
105→      return session.main_agent;
106→    }
107→
108→    // 递归检查所有子智能体
109→    return findInSubAgents(session.main_agent.sub_agents, sysPrompt, messageHistory);
110→  }
111→
112→  /**
113→   * 判断请求是否匹配主智能体
114→   */
115→  matchesMainAgent(
116→    session: Session,
117→    sysPrompt: unknown,
118→    messageHistory: AnthropicMessage[],
119→  ): boolean {
120→    return matchesAgent(session.main_agent, sysPrompt, messageHistory);
121→  }
122→
123→  // ── 子智能体 ────────────────────────────────────────────────────────────────
124→
125→  /**
126→   * 查找能关联到新子智能体的父 agent
127→   * 遍历所有 agent 的 tools_call_result_map，找到：
128→   *   tool_name == "Agent" && is_finished == false && arguments.prompt IN userMessage
129→   */
130→  findParentForSubAgent(
131→    session: Session,
132→    firstUserMessageContent: string,
133→  ): { parentAgent: AgentBase; toolCallId: string } | null {
134→    // 检查主智能体
135→    const mainResult = findAgentToolCall(session.main_agent, firstUserMessageContent);
136→    if (mainResult) return mainResult;
137→
138→    // 递归检查所有子智能体
139→    return findAgentToolCallInSubAgents(session.main_agent.sub_agents, firstUserMessageContent);
140→  }
141→
142→  /**
143→   * 创建子智能体并挂载到父 agent
144→   * agent_id 直接使用 toolCallId（父 agent 的 Agent tool_use id）
145→   */
146→  createSubAgent(
147→    parentAgent: AgentBase,
148→    toolCallId: string,
149→    prompt: string,
150→    sysPrompt: unknown,
151→    messages: AnthropicMessage[],
152→    tools: unknown[],
153→  ): SubAgent {
154→    const subAgent: SubAgent = {
155→      agent_id: toolCallId,
156→      prompt,
157→      is_finished: false,
158→      current_sys_prompt: sysPrompt,
159→      current_messages: [],
160→      tools,
161→      tools_call_result_map: {},
162→      sub_agents: [],
163→    };
164→
165→    // 挂载到父 agent
166→    if ('sub_agents' in parentAgent) {
167→      (parentAgent as MainAgent | SubAgent).sub_agents.push(subAgent);
168→    }
169→
170→    return subAgent;
171→  }
172→
173→  /**
174→   * 在响应阶段检测到 Agent tool_use 时，立即创建占位子智能体
175→   * agent_id = toolCallId，占位节点 messages/tools/sys_prompt 为空
176→   */
177→  createPlaceholderSubAgent(
178→    parentAgent: AgentBase,
179→    toolCallId: string,
180→    prompt: string,
181→  ): SubAgent {
182→    const subAgent: SubAgent = {
183→      agent_id: toolCallId,
184→      prompt,
185→      is_finished: false,
186→      current_sys_prompt: null,
187→      current_messages: [],
188→      tools: [],
189→      tools_call_result_map: {},
190→      sub_agents: [],
191→    };
192→
193→    if ('sub_agents' in parentAgent) {
194→      (parentAgent as MainAgent | SubAgent).sub_agents.push(subAgent);
195→    }
196→
197→    return subAgent;
198→  }
199→
200→  /**
201→   * 在 agent 的直接 sub_agents 中按 agent_id（= tool_call_id）查找
202→   * 用于将已有占位节点与后续到达的真实请求关联
203→   */
204→  findSubAgentByToolCallId(
205→    parentAgent: AgentBase,
206→    toolCallId: string,
207→  ): SubAgent | null {
208→    if (!('sub_agents' in parentAgent)) return null;
209→    const subs = (parentAgent as MainAgent | SubAgent).sub_agents;
210→    return subs.find(s => s.agent_id === toolCallId) ?? null;
211→  }
212→
213→  /**
214→   * 标记子智能体为已完成
215→   * 在 agent 的 sub_agents 中按 agent_id（= tool_call_id）查找并更新
216→   */
217→  markSubAgentFinished(agent: AgentBase, toolCallId: string): void {
218→    if (!('sub_agents' in agent)) return;
219→    const subs = (agent as MainAgent | SubAgent).sub_agents;
220→    const sub = subs.find(s => s.agent_id === toolCallId);
221→    if (sub) {
222→      sub.is_finished = true;
223→    }
224→  }
225→
226→  // ── 重命名 Session ──────────────────────────────────────────────────────────
227→
228→  renameSession(sessionId: string, newName: string): boolean {
229→    const session = this.sessions.get(sessionId);
230→    if (!session) return false;
231→    // session_name 最多 10 个字符
232→    session.session_name = newName.length > 10 ? newName.slice(0, 10) : newName;
233→    session.updated_at = new Date().toISOString();
234→    return true;
235→  }
236→
237→  // ── 删除 Session（内存） ──────────────────────────────────────────────────────
238→
239→  removeSession(sessionId: string): boolean {
240→    return this.sessions.delete(sessionId);
241→  }
242→
243→  // ── 更新时间戳 ──────────────────────────────────────────────────────────────
244→
245→  touch(session: Session): void {
246→    session.updated_at = new Date().toISOString();
247→  }
248→
249→  // ── 统计更新 ─────────────────────────────────────────────────────────────────
250→
251→  updateStats(
252→    session: Session,
253→    model: string,
254→  ): void {
255→    const s = session.stats;
256→    s.total_requests++;
257→    s.models_used[model] = (s.models_used[model] ?? 0) + 1;
258→  }
259→}
260→
261→// ============================================================================
262→// 内部工具函数
263→// ============================================================================
264→
265→function createEmptyStats(): SessionStats {
266→  return {
267→    total_requests: 0,
268→    models_used: {},
269→  };
270→}
271→
272→/**
273→ * 匹配用的头部消息数量上限
274→ *
275→ * 只比较 current_messages 和 messageHistory 的前 HEAD_MATCH_COUNT 条消息，
276→ * 加上 sys_prompt 一致即视为匹配。
277→ *
278→ * 为什么这样做：
279→ *   1. 前几条消息是对话的"指纹"，最稳定，不受中途请求失败影响
280→ *   2. 避免全量逐条比较 → 当中间某个请求被 hook 拦截或上游 API 报错时，
281→ *      current_messages 可能被提前(eagerly)更新，导致全量前缀匹配断裂
282→ *   3. O(1) 复杂度，不随对话长度增长
283→ */
284→const HEAD_MATCH_COUNT = 4;
285→
286→/**
287→ * 判断 agent 是否与 (sysPrompt, messageHistory) 匹配
288→ *
289→ * 匹配逻辑：
290→ *   1. sys_prompt 必须一致（忽略 cache_control）
291→ *   2. 比较双方前 HEAD_MATCH_COUNT 条消息（取实际可比较的最小长度）
292→ *      —— 即 min(stored.length, incoming.length, HEAD_MATCH_COUNT)
293→ *   3. 至少有 1 条消息能比较，或者双方都为空
294→ *
295→ * 注意：Claude Code 会动态给消息 block 加 cache_control 字段，
296→ *       同一条消息在不同请求中 cache_control 位置不同，
297→ *       所以比较时必须忽略 cache_control
298→ */
299→function matchesAgent(
300→  agent: AgentBase,
301→  sysPrompt: unknown,
302→  messageHistory: AnthropicMessage[],
303→): boolean {
304→  // Step 1: sys_prompt 必须一致
305→  if (!deepEqualIgnoreCache(agent.current_sys_prompt, sysPrompt)) {
306→    return false;
307→  }
308→
309→  const storedLen = agent.current_messages.length;
310→  const incomingLen = messageHistory.length;
311→
312→  // 双方都为空 → 仅凭 sys_prompt 匹配（新建 session 的首次请求）
313→  if (storedLen === 0 && incomingLen === 0) {
314→    return true;
315→  }
316→
317→  // 一方有消息一方没有 → 仍然允许（agent 刚创建还没存消息，或压缩后清空了）
318→  if (storedLen === 0 || incomingLen === 0) {
319→    return true;
320→  }
321→
322→  // Step 2: 比较前 HEAD_MATCH_COUNT 条消息
323→  const compareLen = Math.min(storedLen, incomingLen, HEAD_MATCH_COUNT);
324→
325→  for (let i = 0; i < compareLen; i++) {
326→    if (!deepEqualIgnoreCache(agent.current_messages[i], messageHistory[i])) {
327→      return false;
328→    }
329→  }
330→
331→  return true;
332→}
333→
334→/**
335→ * 深度比较，忽略 cache_control 字段
336→ */
337→function deepEqualIgnoreCache(a: unknown, b: unknown): boolean {
338→  return JSON.stringify(a, cacheReplacer) === JSON.stringify(b, cacheReplacer);
339→}
340→
341→function cacheReplacer(key: string, value: unknown): unknown {
342→  if (key === 'cache_control') return undefined;
343→  return value;
344→}
345→
346→/**
