134→// ============================================================================
135→// 文本提取工具
136→// ============================================================================
137→
138→/**
139→ * 从 Anthropic system 字段（数组或字符串）中提取纯文本
140→ * 用于压缩恢复时的摘要匹配
141→ */
142→function extractSystemText(system: unknown): string {
143→  if (typeof system === 'string') return system;
144→  if (Array.isArray(system)) {
145→    return system
146→      .filter((b: unknown) => typeof b === 'object' && b !== null && (b as Record<string, unknown>).type === 'text' && typeof (b as Record<string, unknown>).text === 'string')
147→      .map((b: unknown) => (b as Record<string, string>).text)
148→      .join('\n');
149→  }
150→  return '';
151→}
152→
153→/**
154→ * 仅提取消息中 text 类型 block 的文本（不包含 tool_result）
155→ * 用于压缩指令检测，避免 tool_result 中的文件内容导致误判
156→ */
157→function getTextOnlyContent(msg: AnthropicMessage): string {
158→  if (typeof msg.content === 'string') return msg.content;
159→  if (Array.isArray(msg.content)) {
160→    return msg.content
161→      .filter(block => block.type === 'text' && block.text)
162→      .map(block => block.text)
163→      .join('\n');
164→  }
165→  return '';
166→}
167→
168→/**
169→ * 提取消息的完整文本内容（包括所有 text blocks 和 tool_result）
170→ */
171→function getFullMessageText(msg: AnthropicMessage): string {
172→  if (typeof msg.content === 'string') return msg.content;
173→  if (Array.isArray(msg.content)) {
174→    return msg.content
175→      .map(block => {
176→        if (block.type === 'text' && block.text) return block.text;
177→        if (block.type === 'tool_result' && typeof block.content === 'string') return block.content;
178→        return '';
179→      })
180→      .join('\n');
181→  }
182→  return '';
183→}
184→
185→/**
186→ * 获取 messages 中首条 user message 的文本内容
187→ * 用于子智能体关联（prompt IN user_message 匹配）
188→ */
189→function getFirstUserMessageText(messages: AnthropicMessage[]): string {
190→  const firstUser = messages.find(m => m.role === 'user');
191→  return firstUser ? getFullMessageText(firstUser) : '';
192→}
193→
194→export { getFullMessageText, extractSystemText };
